content.text:
body {
  font-family: "Inter", system-ui, -apple-system, BlinkMacSystemFont,
               "Segoe UI", Roboto, sans-serif;
}

code, pre {
  font-family: "Fira Code", "Cascadia Code", ui-monospace,
               "Courier New", monospace;
}

.serif-heading {
  font-family: "Playfair Display", Georgia, "Times New Roman", serif;
}

/* Absolute */
.label  { font-size: 12px; }

/* Relative to root (preferred for accessibility) */
h1 { font-size: 2rem; }     /* 32px if root is 16px */
h2 { font-size: 1.5rem; }   /* 24px */
p  { font-size: 1rem; }     /* 16px */

/* Relative to parent (use with caution — compounds) */
.nested { font-size: 0.875em; }

/* Fluid — scales with viewport */
h1 { font-size: clamp(1.75rem, 4vw + 0.5rem, 3rem); }

/* Named keywords */
.small { font-size: small; }    /* ~13px */
.large { font-size: large; }    /* ~18px */

h1 { font-weight: 700; }
h2 { font-weight: 600; }
p  { font-weight: 400; }  /* normal */

/* Keywords */
strong { font-weight: bold; }   /* = 700 */
.light  { font-weight: lighter; } /* relative to parent */

em    { font-style: italic; }
cite  { font-style: italic; }
.normal { font-style: normal; }
.oblique { font-style: oblique 15deg; } /* slant without true italic */

/* font: [style] [variant] [weight] [stretch] size/line-height family */
p {
  font: 400 1rem/1.6 "Inter", system-ui, sans-serif;
}

h1 {
  font: 700 2rem/1.2 "Playfair Display", Georgia, serif;
}

/* IMPORTANT: font shorthand resets ALL font sub-properties to initial.
   Use individual properties when you only want to change some. */

.heading-large {
  letter-spacing: -0.02em;  /* tight tracking for large headings */
}

.caps-label {
  text-transform: uppercase;
  letter-spacing: 0.08em;   /* spread uppercase letters */
  font-size: 0.75rem;
}

.body-text {
  /* Usually leave at default 0 — let the font's built-in kerning handle it */
  letter-spacing: 0;
}

.spaced-words {
  word-spacing: 0.1em;
}

p     { text-align: left; }          /* default in LTR */
.centered { text-align: center; }
.right    { text-align: right; }
.justified { text-align: justify; } /* avoid in most UI — creates rivers */

/* Logical properties (LTR/RTL safe) */
p { text-align: start; }   /* left in LTR, right in RTL */
p { text-align: end; }

/* Indent first line */
.article p {
  text-indent: 1.5em;
}

a { text-decoration: underline; }
a:hover { text-decoration: none; }

/* Detailed control */
a {
  text-decoration-line: underline;
  text-decoration-color: oklch(0.6 0.2 260 / 0.4);  /* subtle color */
  text-decoration-style: solid;     /* solid | dashed | dotted | wavy | double */
  text-decoration-thickness: 2px;
  text-underline-offset: 3px;      /* gap between baseline and underline */
}

.strikethrough { text-decoration: line-through; }
.overline      { text-decoration: overline; }

/* Single-line truncation with ellipsis */
.truncate {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 200px;
}

/* Multi-line clamp (CSS only, no JS) */
.clamp-3 {
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* Prevent long URLs from breaking layout */
.url-field {
  overflow-wrap: break-word;
  word-break: break-all;
}

h1, h2, h3 {
  text-wrap: balance;  /* equalize line lengths — prevents lone word on last line */
}

p {
  text-wrap: pretty;   /* avoid orphans at paragraph end */
}

/* In styles.css or a _fonts.scss partial */
@font-face {
  font-family: "Inter";
  src: url("/assets/fonts/inter-variable.woff2") format("woff2");
  font-weight: 100 900;     /* variable font — full weight range */
  font-style: normal;
  font-display: swap;       /* show fallback until font loads */
}

@font-face {
  font-family: "Inter";
  src: url("/assets/fonts/inter-variable-italic.woff2") format("woff2");
  font-weight: 100 900;
  font-style: italic;
  font-display: swap;
}

/* styles.scss */
:root {
  --font-sans: "Inter", system-ui, sans-serif;
  --font-mono: ui-monospace, "Fira Code", monospace;
}

body {
  font-family: var(--font-sans);
  font-size: 1rem;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* src/styles.scss */
:root {
  /* Scale */
  --text-xs:   0.75rem;    /* 12px */
  --text-sm:   0.875rem;   /* 14px */
  --text-base: 1rem;       /* 16px */
  --text-lg:   1.125rem;   /* 18px */
  --text-xl:   1.25rem;    /* 20px */
  --text-2xl:  1.5rem;     /* 24px */
  --text-3xl:  1.875rem;   /* 30px */
  --text-4xl:  2.25rem;    /* 36px */

  /* Weights */
  --weight-normal:   400;
  --weight-medium:   500;
  --weight-semibold: 600;
  --weight-bold:     700;

  /* Leading */
  --leading-tight:  1.25;
  --leading-snug:   1.375;
  --leading-normal: 1.5;
  --leading-relaxed: 1.625;
}

/* Base styles */
body {
  font-family: var(--font-sans);
  font-size: var(--text-base);
  font-weight: var(--weight-normal);
  line-height: var(--leading-normal);
  color: var(--color-text);
}

h1 { font-size: var(--text-4xl); font-weight: var(--weight-bold);    line-height: var(--leading-tight); }
h2 { font-size: var(--text-3xl); font-weight: var(--weight-bold);    line-height: var(--leading-tight); }
h3 { font-size: var(--text-2xl); font-weight: var(--weight-semibold); line-height: var(--leading-snug); }
h4 { font-size: var(--text-xl);  font-weight: var(--weight-semibold); line-height: var(--leading-snug); }

/* button.component.scss */
:host {
  font-size: var(--text-sm);
  font-weight: var(--weight-semibold);
  letter-spacing: 0.01em;
}

h1 {
  /* min 1.75rem, fluid between viewports, max 3.5rem */
  font-size: clamp(1.75rem, 3vw + 1rem, 3.5rem);
}

h2 {
  font-size: clamp(1.5rem, 2.5vw + 0.75rem, 2.5rem);
}

body {
  /* Body text: never smaller than 1rem, never larger than 1.125rem */
  font-size: clamp(1rem, 1.5vw, 1.125rem);
}

/* Numeric variants */
.price {
  font-variant-numeric: tabular-nums;    /* fixed-width digits — aligns in tables */
}

.footnote {
  font-variant-numeric: oldstyle-nums;   /* old-style figures (drop below baseline) */
}

/* Small caps */
.dropcap {
  font-variant-caps: small-caps;
}

/* Low-level OpenType via font-feature-settings */
.ligatures {
  font-feature-settings: "liga" 1, "calt" 1;   /* ligatures + contextual alternates */
}

.prose {
  max-width: 65ch;          /* optimal reading measure */
  line-height: 1.6;
  hyphens: auto;            /* language-aware hyphenation */
  overflow-wrap: break-word; /* prevent overflow on narrow screens */
}
